 declare(strict_types=1); namespace League\CommonMark\Extension\Footnote\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Renderer\BlockRendererInterface; use League\CommonMark\ElementRendererInterface; use League\CommonMark\Extension\Footnote\Node\FootnoteContainer; use League\CommonMark\HtmlElement; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class FootnoteContainerRenderer implements BlockRendererInterface, ConfigurationAwareInterface { private $config; public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof FootnoteContainer)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } $attrs = $block->getData('attributes', []); $attrs['class'] = $attrs['class'] ?? $this->config->get('footnote/container_class', 'footnotes'); $attrs['role'] = 'doc-endnotes'; $contents = new HtmlElement('ol', [], $htmlRenderer->renderBlocks($block->children())); if ($this->config->get('footnote/container_add_hr', true)) { $contents = [new HtmlElement('hr', [], null, true), $contents]; } return new HtmlElement('div', $attrs, $contents); } public function setConfiguration(ConfigurationInterface $configuration) { $this->config = $configuration; } } 